import streamlit as st
 
st.title ("Calculadora ")
st.subheader("Feito com streamlit")

altura = st.number_input("Digite a sua altura", min_value=0.0)
peso = st.number_input("Digite o seu peso", min_value=0.0)

if st.button("calcular"):
    # imc = peso / altura ** 2
    #st.sucess (f"Seu IMC é {imc:.2f}")
    imc = peso / altura ** 2 
    st.success(f"Seu Imc é {imc:.2f}")
    if imc < 18.5:
        st.error("Abaixo do peso")
        st.image("https://i1.sndcdn.com/artworks-DW1YYdgHCvkmy0Hb-z69Rhw-t500x500.jpg")
    elif imc < 24.9:
        st.success("Peso anormal")
        st.image("https://media.tenor.com/gyuqx70UjmEAAAAe/emoji-feliz-ficando-triste-emoticon-feliz-ficando-triste.png")
    elif imc < 29.9:
        st.error("sobrepeso")
        st.image("data:image/jpeg;base64,")
    elif imc < 34.4:
        st.error("Obesidade Grau 1")
        st.image("data:image/jpeg;base64,")
    elif imc < 39.9:
        st.error("Obesidade Grau 2")
        st.image("https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTJ20YmfzJBPSCKyHOQHwEF2CEihdEa8BDCtg&s")
    else:
        st.error("Obesidade Grau 3")
        st.image("data:image/jpeg;base64,")